import { TinyColor } from '@ctrl/tinycolor';
import type { Color } from '../types';

// 暗色主题颜色映射关系表
const darkColorMap = [
  { index: 9, s: 0.92, v: -0.1, level: 50 },
  { index: 9, s: 0.92, v: -0.05, level: 100 },
  { index: 8, s: 0.92, v: -0.05, level: 200 },
  { index: 7, s: 0.92, v: -0.05, level: 300 },
  { index: 6, s: 0.92, v: 0.01, level: 400 },
  { index: 5, s: 0.92, v: 0.01, level: 500 }, // ok
  { index: 4, s: 0.92, v: 0.01, level: 600 }, // ok
  { index: 3, s: 0.92, v: 0.01, level: 700 },
  { index: 2, s: 0.92, v: 0.01, level: 800 },
  { index: 1, s: 0.92, v: 0.01, level: 900 },
];

export default (lightColors: Color[]): Color[] =>
  darkColorMap.map(({ index, s: sMount, v: vMount, level }) => {
    const { value } = lightColors[index];
    const { h, s, v } = new TinyColor(value).toHsv();
    const darkColorString = new TinyColor({
      h,
      s: s * sMount,
      v: Math.max(Math.min(v + vMount, 1), 0),
    }).toHexString();
    return {
      level,
      value: darkColorString,
    };
  });
